// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.LinkedHashSet;
import java.util.Set;

import org.junit.jupiter.api.Test;

class BindingMaskTest {

	@Test
	void masksSupportMoreThanSixtyFourSymbols() {
		BindingUniverse universe = BindingUniverse.create();
		for (int i = 0; i < 130; i++) {
			assertEquals(i, universe.intern("v" + i).id());
		}

		BindingMask left = universe.maskOf(Set.of("v0", "v63", "v64", "v129"));
		BindingMask right = universe.maskOf(Set.of("v1", "v64", "v127", "v129"));

		assertEquals(4, left.size());
		assertTrue(left.contains(universe.symbol("v64")));
		assertTrue(left.intersects(right));
		assertEquals(Set.of("v64", "v129"), universe.names(left.intersect(right)));
		assertEquals(Set.of("v0", "v63"), universe.names(left.minus(right)));
		assertTrue(left.union(right).containsAll(universe.maskOf(Set.of("v0", "v1", "v64", "v127", "v129"))));
		assertEquals(0, left.nextSetBit(0));
		assertEquals(63, left.nextSetBit(1));
		assertEquals(64, left.nextSetBit(64));
		assertEquals(129, left.nextSetBit(65));
		assertEquals(-1, left.nextSetBit(130));
	}

	@Test
	void universeFiltersNonPlannerNamesAtMaskBoundary() {
		BindingUniverse universe = BindingUniverse.create();

		BindingMask mask = universe.maskOf(new LinkedHashSet<>(Set.of("s", "_const_x", "", "   ", "o")));

		assertEquals(Set.of("s", "o"), universe.names(mask));
		assertFalse(universe.containsName("_const_x"));
		assertFalse(universe.containsName(""));
	}
}
